SELECT ?city WHERE {
  ?event_c wdt:P710 wd:Q1708938 ;
           wdt:P710 ?X ;
           wdt:P580 ?date_c ;
           wdt:P276 ?city.

  ?event_d wdt:P710 wd:Q1162702 ;
           wdt:P710 ?X ;
           wdt:P580 ?date_d.

  ?event_s wdt:P710 wd:Q1317402 ;
           wdt:P710 ?X ;
           wdt:P580 ?date_s.

  FILTER (isNumeric(?date_c))
  FILTER (isNumeric(?date_d))
  FILTER (isNumeric(?date_s))
}
ORDER BY ASC(?date_c)
LIMIT 1

SELECT ?city WHERE {
  ?match_c wdt:P710 wd:Q1708938 ;
             wdt:P710 ?x.

  ?match_d wdt:P710 ?x ;
           wdt:P710 wd:Q1162702 ;
           wdt:P580 ?date_d ;
           wdt:P276 ?city_d.

  ?match_s wdt:P710 ?x ;
           wdt:P710 wd:Q1317402 ;
           wdt:P580 ?date_s ;
           wdt:P276 ?city_s.

  BIND(min(?date_d, ?date_s) AS ?earliest_date)
  FILTER (?earliest_date = ?date_d || ?earliest_date = ?date_s)

  BIND(COALESCE(?city_d, ?city_s) AS ?city)
}
ORDER BY ?earliest_date
LIMIT 1

